<template>
  <div class="dashboard-editor-container">

    <loader v-if="loading"/>
    <panel-group-summary v-if="!loading"/>

    <el-row style="background:#fff;padding:16px 16px 16px;margin-bottom:10px;margin-top: 20px">
      <line-chart v-if="!loading" :chart-data="lineChartData"/>
    </el-row>

    <tabs v-if="!loading" style="margin-top: 25px"/>

  </div>
</template>

<script>
import GithubCorner from '@/components/GithubCorner'
import PanelGroupSummary from './components/PanelGroupSummary'
import LineChart from './components/LineChart'
import tabs from './components/Tabs'
import Loader from './components/Loader'
import { mapActions, mapGetters } from 'vuex'

export default {
  name: 'DashboardAdmin',
  components: {
    Loader,
    PanelGroupSummary,
    GithubCorner,
    LineChart,
    tabs
  },
  data() {
    return {
      loading: true
    }
  },
  computed: {
    ...mapGetters('automationUsage', ['lineChartData'])
  },
  created() {
    this.getLineChartData().then((value) => {
      this.loading = false
    })
  },
  methods: {
    ...mapActions('automationUsage', ['getLineChartData'])
  }
}
</script>

<style rel="stylesheet/scss" lang="scss" scoped>
  .dashboard-editor-container {
    padding: 32px;
    background-color: rgb(240, 242, 245);
    .chart-wrapper {
      background: #fff;
      padding: 16px 16px 0;
      margin-bottom: 32px;
    }
  }
</style>
